import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"研究主題：大道至簡 — Claude Cost & Efficiency 最佳實踐","description":"","frontmatter":{"date":"2026-05-12T00:00:00.000Z","depth":"D2","sources":"research/papers/ + research/tweets/ + research/best-practices/","topic":"大道至簡 — Claude Best Practices / Cost & Efficiency Optimization","verify":"V1+V2"},"headers":[],"relativePath":"research/reports/2026-05-12-best-practices-simplicity.md","filePath":"research/reports/2026-05-12-best-practices-simplicity.md","lastUpdated":1779894392000}'),d={name:"research/reports/2026-05-12-best-practices-simplicity.md"};function i(n,t,s,c,l,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="研究主題-大道至簡-—-claude-cost-efficiency-最佳實踐" tabindex="-1">研究主題：大道至簡 — Claude Cost &amp; Efficiency 最佳實踐 <a class="header-anchor" href="#研究主題-大道至簡-—-claude-cost-efficiency-最佳實踐" aria-label="Permalink to &quot;研究主題：大道至簡 — Claude Cost &amp; Efficiency 最佳實踐&quot;">​</a></h1><h2 id="信度分層摘要" tabindex="-1">信度分層摘要 <a class="header-anchor" href="#信度分層摘要" aria-label="Permalink to &quot;信度分層摘要&quot;">​</a></h2><h3 id="o-官方-anthropic-一手資料" tabindex="-1">[O] 官方 / Anthropic 一手資料 <a class="header-anchor" href="#o-官方-anthropic-一手資料" aria-label="Permalink to &quot;[O] 官方 / Anthropic 一手資料&quot;">​</a></h3><ul><li><strong>CLAUDE.md budget</strong>: bcherny 明示 ≤60 行最佳，≤200 行上限。超過後模型注意力稀釋 → 有效規則密度下降。</li><li><strong>Prompt Caching 五原則</strong>（bcherny）：Static first, dynamic last；工具列表與模型 mid-session 不可改；<code>defer_loading: true</code> 保持 cache prefix 穩定。Cache hit = 0.1× 費率，write = 1.25× 費率。</li><li><strong>Context Engineering</strong>（Karpathy）：「填充恰好所需的資訊」是核心；too much context = 成本上升 + 品質下降，不是越多越好。</li><li><strong>Output Discipline 實測</strong>：英文 -80.6%、繁中 -86.2% 輸出 token，LLM Judge 品質無衰退（T-B/T-C/T-D 驗證 2026-04-30）。</li></ul><h3 id="c-社群觀察-未官方確認" tabindex="-1">[C] 社群觀察（未官方確認） <a class="header-anchor" href="#c-社群觀察-未官方確認" aria-label="Permalink to &quot;[C] 社群觀察（未官方確認）&quot;">​</a></h3><ul><li><strong>Contextmaxxing vs Tokenmaxxing</strong>（ashwingop/Sentra）：compiled memory 可減少 50–98% token；「right context &gt; more context」。⚠️ 幅度數字為特定應用實測，不可直接套用。</li><li><strong>Tool saturation</strong>（nicbstme）：~20 工具飽和閾值；combined agents+MCP 約 15。超過後 routing 精度明顯下降。</li><li><strong>AgentOpt</strong>（P-tier 研究）：Weak planner + strong solver pattern → 13–32× 成本差距。</li><li><strong>Context rot 閾值</strong>（Thariq @trq212）：約 300–400k tokens 開始影響輸出品質。⚠️ 社群觀察，高度任務依賴。</li></ul><h3 id="e-行業報告" tabindex="-1">[E] 行業報告 <a class="header-anchor" href="#e-行業報告" aria-label="Permalink to &quot;[E] 行業報告&quot;">​</a></h3><ul><li><strong>DeepMind 多代理協調研究（2025）</strong>：Baseline &gt; 80% 加代理反降性能；Coordination Tax 在 ≥4 agents 飽和；Bag-of-Agents 17.2× 錯誤放大。</li></ul><h2 id="來源驗證結果" tabindex="-1">來源驗證結果 <a class="header-anchor" href="#來源驗證結果" aria-label="Permalink to &quot;來源驗證結果&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Claim</th><th>來源層</th><th>狀態</th><th>備注</th></tr></thead><tbody><tr><td>≤60 行 optimal CLAUDE.md</td><td>O (bcherny)</td><td>✅ confirmed</td><td>cc-workspace CLAUDE.md 81 行，超過但在 200 行預算內</td></tr><tr><td>Prompt caching 0.1× hit rate</td><td>O (Anthropic docs)</td><td>✅ confirmed</td><td>官方定價頁</td></tr><tr><td>-80.6% output token</td><td>O (內部實測)</td><td>✅ confirmed</td><td>output-discipline.md 已實作</td></tr><tr><td>Tool saturation ~20</td><td>C (nicbstme)</td><td>⚠️ unverified</td><td>單一社群觀察，無 replications</td></tr><tr><td>Context rot 300-400k</td><td>C (Thariq)</td><td>⚠️ unverified</td><td>社群觀察，任務高度依賴</td></tr><tr><td>50-98% token 節省</td><td>C (ashwingop)</td><td>⚠️ unverified</td><td>特定應用，幅度不通用</td></tr></tbody></table><h2 id="大道至簡核心發現" tabindex="-1">大道至簡核心發現 <a class="header-anchor" href="#大道至簡核心發現" aria-label="Permalink to &quot;大道至簡核心發現&quot;">​</a></h2><h3 id="主論點" tabindex="-1">主論點 <a class="header-anchor" href="#主論點" aria-label="Permalink to &quot;主論點&quot;">​</a></h3><p><strong>加法思維是效率陷阱</strong>。研究一致指向：更少的、更精確的 context &gt; 更多的 context；更強的 prompt &gt; 更多的 agent；更好的工具設計 &gt; 更多的工具。</p><h3 id="量化基準-本-workspace-套用" tabindex="-1">量化基準（本 workspace 套用） <a class="header-anchor" href="#量化基準-本-workspace-套用" aria-label="Permalink to &quot;量化基準（本 workspace 套用）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>前（本次研究前）</th><th>後（本次改動）</th><th>來源</th></tr></thead><tbody><tr><td>subagent-strategy.md 行數</td><td>137 行</td><td>91 行 (−34%)</td><td>本次 prune pass</td></tr><tr><td>Auto-loaded rules 總行數</td><td>348 行</td><td>~302 行</td><td>本次 prune pass</td></tr><tr><td>PermissionRequest 審計覆蓋</td><td>無</td><td>有 (audit-permission.sh)</td><td>上一 session 補充</td></tr><tr><td>Tool schema lint</td><td>無</td><td>有 (session-init.sh)</td><td>上一 session 補充</td></tr><tr><td>Compact hint 指引</td><td>無</td><td>有 (context-management.md)</td><td>上一 session 補充</td></tr></tbody></table><h3 id="大道至簡-prune-test-應用於本-workspace" tabindex="-1">大道至簡 Prune Test（應用於本 workspace） <a class="header-anchor" href="#大道至簡-prune-test-應用於本-workspace" aria-label="Permalink to &quot;大道至簡 Prune Test（應用於本 workspace）&quot;">​</a></h3><p><strong>測試問題</strong>：「移除這條規則，過去是否會發生具體失敗？」</p><table tabindex="0"><thead><tr><th>移除內容</th><th>Pass test?</th><th>行動</th></tr></thead><tbody><tr><td>45% 規則完整表格（30 行）</td><td>✅ 可移除</td><td>壓縮為 1 行摘要 + ref 指標</td></tr><tr><td>5D Coordination Layer 規格表</td><td>✅ 可移除</td><td>行為約束已在 7-row topology 表內</td></tr><tr><td>任務-拓撲匹配完整表格</td><td>✅ 可移除</td><td>PlanCraft -39% 已在 Known Gotchas 保留</td></tr><tr><td>&quot;跳過 45% 量化&quot; gotcha</td><td>✅ 可移除</td><td>與壓縮後摘要重複</td></tr><tr><td>生產環境安全紅線</td><td>❌ 不可移除</td><td>高風險操作必要約束</td></tr><tr><td>Git commit session URL 強制</td><td>❌ 不可移除</td><td>無 hook 時容易漏，hook 也依賴規則提醒</td></tr><tr><td>Monitor 策略</td><td>❌ 不可移除</td><td>不設會造成長時間無回應</td></tr></tbody></table><h2 id="架構建議-下一步-非本次實作" tabindex="-1">架構建議（下一步 / 非本次實作） <a class="header-anchor" href="#架構建議-下一步-非本次實作" aria-label="Permalink to &quot;架構建議（下一步 / 非本次實作）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>優先序</th><th>建議</th><th>預期效益</th><th>複雜度</th></tr></thead><tbody><tr><td>A1</td><td>Memory Layering：區分 session memory / project memory / global memory</td><td>減少 session 載入 token</td><td>中</td></tr><tr><td>A2</td><td>Semantic Compact hint 模板：為常見任務類型預建 compact hint</td><td>減少 Lost-in-Middle 損耗</td><td>低</td></tr><tr><td>A3</td><td>AgentOpt 模式：識別 planner vs solver 分離點，降級 planner 模型</td><td>13–32× 成本差距</td><td>高</td></tr></tbody></table><h2 id="輸出建議" tabindex="-1">輸出建議 <a class="header-anchor" href="#輸出建議" aria-label="Permalink to &quot;輸出建議&quot;">​</a></h2><ul><li>本次研究 → <strong>已實作</strong>（prune pass 完成，見上表）</li><li>A1-A3 → <strong>未來 session</strong>，複雜度較高，需單獨規劃</li></ul><hr><p><em>驗證：V1 self-check 完成（所有 claim 有標注）；V2 cross-check：output-discipline 實測數字來自同 workspace 驗證，可信度高。</em></p><hr><h2 id="最終論-final-pass-—-2026-05-12" tabindex="-1">最終論（Final Pass）— 2026-05-12 <a class="header-anchor" href="#最終論-final-pass-—-2026-05-12" aria-label="Permalink to &quot;最終論（Final Pass）— 2026-05-12&quot;">​</a></h2><p>三向平行 researcher（best-practices/papers/tweets）再次掃描，共發現 6 個候選 gap，advisor 逐項裁決：</p><table tabindex="0"><thead><tr><th>Gap</th><th>裁決</th><th>原因（prune test）</th></tr></thead><tbody><tr><td>CLAUDE.md 自更新 prompt suffix</td><td>REJECT</td><td>core.md 已有犯錯記錄原則；遞迴 meta-bloat</td></tr><tr><td>Permission Hook Opus 自動核准</td><td>REJECT</td><td>solo interactive：Opus roundtrip 5–10s &gt; 人工 1s；未來 batch 模式再評估</td></tr><tr><td>Dreaming / Offline Learning</td><td>REJECT</td><td>誤機制：dreaming 是 online agent，非 session-stop logger；人工 Known Gotcha = 正確替代</td></tr><tr><td><code>--from-pr</code> PR 恢復</td><td>REJECT</td><td>CLI feature，非行為規則；需要時加入 playbook 即可</td></tr><tr><td>Keep Rate 度量</td><td>REJECT</td><td>logging ≠ closed-loop；solo workspace 無品質退化未被發現的歷史證據</td></tr><tr><td>TSCG Tool Schema 壓縮</td><td>DEFER</td><td>觸發條件（&gt;10 MCP tools）未滿足；條件滿足時重新評估</td></tr></tbody></table><p><strong>Advisor meta-verdict</strong>：優化已達穩態。下一條有價值的規則來自「實際使用中發現規則失效」，而非再一輪研究掃描。宣告大道至簡優化完成。</p><hr><p><em>🔄 overnight-research 驗證：2026-05-23 — 本文件為 workspace 內部分析（tweets/best-practices 本地資料），不依賴可即時更新的外部官方資料。狀態：已確認現行有效。</em></p><hr><h2 id="_2026-05-25-re-check" tabindex="-1">2026-05-25 Re-check <a class="header-anchor" href="#_2026-05-25-re-check" aria-label="Permalink to &quot;2026-05-25 Re-check&quot;">​</a></h2><blockquote><p><strong>方法</strong>：對照 <code>.claude/rules/</code> 4 個 auto-load 規則的現狀，核查大道至簡原則在架構建議（A1–A3）的落地情況，並結合 <code>2026-05-25-papers-analysis.md</code> 新論文驗證核心主張。</p></blockquote><h3 id="已落地的建議-✅" tabindex="-1">已落地的建議（✅） <a class="header-anchor" href="#已落地的建議-✅" aria-label="Permalink to &quot;已落地的建議（✅）&quot;">​</a></h3><p><strong>核心主張驗證</strong></p><ul><li>✅ CLAUDE.md ≤ 200 行上限：workspace CLAUDE.md 已控制在預算內（4 個 auto-load 規則 + 參照格式，符合 ≤200 行設計）</li><li>✅ Prompt Caching 三禁止：<code>context-management.md</code> 已明文（mid-session 禁止切換模型/工具/CLAUDE.md）</li><li>✅ Output Discipline 實測（英文 -80.6%、繁中 -86.2%）：<code>output-discipline.md</code> 已完整實作，無開場白 + 填充語禁止 + ≤150 字上限</li><li>✅ Compact 三層觸發（行為信號 &gt; 數字閾值 &gt; 定時器）：<code>context-management.md</code> 已落地</li><li>✅ Compact hint 格式（保留安全紅線 / 專案慣例 / 關鍵假設；捨棄中間詳情）：<code>context-management.md</code> 已明文</li><li>✅ PermissionRequest 審計（<code>audit-permission.sh</code>）：已在 hooks 目錄實作</li><li>✅ Tool schema lint（<code>session-init.sh</code>）：已在 hooks 目錄實作</li><li>✅ 「移除這條規則，過去是否會發生具體失敗？」剪枝測試：<code>core.md</code> §Framework Integrity 已制度化</li></ul><p><strong>Prune Test 裁決追蹤</strong></p><ul><li>✅ 生產環境安全紅線「不可移除」：<code>core.md</code> 已保留（GCP/TF/K8s 含 prod）</li><li>✅ Monitor 策略「不可移除」：<code>core.md</code> §長任務執行 已保留（Bash &gt;30s → Monitor + run_in_background）</li><li>✅ Git commit session URL 強制「不可移除」：<code>core.md</code> §Git 工作流程 已保留</li></ul><p><strong>架構建議（A1–A3）</strong></p><ul><li>✅ A1 Memory Layering：<code>core.md</code> §長期記憶回路 雙層架構（Auto Memory + MEMORY.md）已落地；<code>refs/memory-layering.md</code> 已建立</li><li>✅ A2 Semantic Compact hint 模板：<code>context-management.md</code> 已有 compact hint 格式規範</li><li>⚠️ A3 AgentOpt（planner vs solver 分離）：<code>subagent-strategy.md</code> 已有模型分層（Haiku executor / Sonnet / Opus），但「降級 planner 模型」的系統化識別流程未完整落地</li></ul><h3 id="待追蹤的-gap-⚠️" tabindex="-1">待追蹤的 gap（⚠️） <a class="header-anchor" href="#待追蹤的-gap-⚠️" aria-label="Permalink to &quot;待追蹤的 gap（⚠️）&quot;">​</a></h3><ul><li>⚠️ <strong>A3 AgentOpt 模式未完全落地</strong>：<code>subagent-strategy.md</code> 的模型選擇以「獨立檔案數」為主要判斷依據（0–1 Haiku / 2–9 Sonnet / 10+ Sonnet/Opus），但 AgentOpt 的「強 solver + 弱 planner」模式（讓 Haiku/Sonnet 規劃，Opus 執行複雜決策）尚未系統化。2026-05-25 論文分析進一步驗證此模式：強模型當 Planner 在某些場景反而降低整體表現。</li><li>⚠️ <strong>Tool saturation ~20 工具閾值仍未驗證</strong>：本報告標注「⚠️ 社群觀察，無 replications」。截至 2026-05-25，workspace MCP server 數量持續增長（Google Drive、GitHub 等），但未追蹤當前實際 MCP tools 總數，不確定是否已接近 ~15（combined agents+MCP）飽和閾值。</li><li>⚠️ <strong>TSCG Tool Schema 壓縮（DEFER 項目）</strong>：最終論裁決「條件滿足時重新評估」。<code>2026-05-25-papers-analysis.md</code> 中 <code>tscg-tool-schema-compilation</code> 論文實測工具模式 52-57% token 節省（Phi-4 從 0%→84.4%）。隨 MCP 工具增長，此 DEFER 項目的評估條件（&gt;10 MCP tools）可能已接近。需重新評估是否觸發。</li><li>⚠️ <strong>Context rot 閾值 300-400k token（⚠️ 社群觀察）</strong>：<code>context-management.md</code> 已採用此閾值作為「定時器」觸發條件，但本報告標注信度為 [C]（未官方確認）。2026-05 論文未提供更精確的實驗數據，仍需觀察。</li></ul><h3 id="新發現的最佳實踐補充-🆕" tabindex="-1">新發現的最佳實踐補充（🆕） <a class="header-anchor" href="#新發現的最佳實踐補充-🆕" aria-label="Permalink to &quot;新發現的最佳實踐補充（🆕）&quot;">​</a></h3><ul><li>🆕 <strong>「right context &gt; more context」獲論文級驗證</strong>：本報告的核心主張「加法思維是效率陷阱」獲 2026-05-25 論文分析強力支持。<code>natural-language-agent-harnesses-2603-25723</code> 實測 NLAH 將 context 從 60.1K → 2.9K token（-95%），效能相當。「填充恰好所需資訊」不再只是經驗法則，而有論文級量化驗證。</li><li>🆕 <strong>「Harness &gt; 模型」對大道至簡的啟示</strong>：論文分析的核心發現「Harness 配置效益超越模型升級」是大道至簡在 AI 編程領域最強的外部驗證：與其升級模型（花費）不如優化 CLAUDE.md + Hooks + Memory 設計（免費）。本報告的「加法思維是效率陷阱」獲得了更廣泛的框架支持。</li><li>🆕 <strong>Bayesian 優化 vs 手工調優的量化反差</strong>：<code>harbor-automated-harness-optimization</code> 論文：Bayesian 優化 9 個配置旗標明顯優於手工調優，且手工調優可能產生退化（-37%）。這是 A3 AgentOpt 模式的新佐證：planner/solver 分工的最優邊界不應靠直覺手工設定，而需要系統性搜索。</li><li>🆕 <strong><code>/goal</code> 命令作為大道至簡的工具化</strong>：<code>/goal</code> 讓 Claude 迭代到達標（R4），減少人工介入的「你完成了嗎？」確認輪次。對需要多輪執行的任務，<code>/goal</code> 是 context 效率的提升工具（減少 prompt 往返）。與大道至簡原則高度契合：一次設定終止條件，而非多次手動 checkpoint。</li><li>🆕 <strong>Sub-agent progress summaries 的 cache 命中（v2.1.128）</strong>：長 agentic 任務的 cache creation token 成本降低約 3×。本報告 §量化基準表格應更新：原先計算 agentic 任務成本的基準假設已不再準確，實際成本低於估算。</li></ul><p><em>Re-check 日期：2026-05-25 | 核心結論：「大道至簡」主張獲 2026 論文級驗證，A1/A2 已落地，A3 部分落地，TSCG DEFER 條件接近觸發</em></p>',46)])])}const g=e(d,[["render",i]]);export{m as __pageData,g as default};
